#include <iostream>
#include <limits>

using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    int max_val = numeric_limits<int>::min();
    int freq = 0;

    for (int i = 0; i < n; ++i) {
        int x;
        cin >> x;
        if (x > max_val) {
            max_val = x;
            freq = 1;
        } else if (x == max_val) {
            ++freq;
        }
    }

    cout << max_val << ' ' << freq << '\n';

    return 0;
}
